<template><div class="grid"><img v-for="(img,i) in images" :src="img" class="thumb reveal" :style="{transitionDelay:(i*120)+'ms'}" @click="open(i)"/></div><div v-if="show" class="full" @click="close"><button class="nav left" @click.stop="prev">⟨</button><img :src="current" class="img-full"/><button class="nav right" @click.stop="next">⟩</button></div></template><script setup>import{ref,computed}from "vue";const props=defineProps({images:Array});const i=ref(0),show=ref(false);const current=computed(()=>props.images[i.value]);const open=j=>{i.value=j;show.value=true;document.body.style.overflow="hidden"};const close=()=>{show.value=false;document.body.style.overflow="auto"};const next=()=>i.value=(i.value+1)%props.images.length;const prev=()=>i.value=(i.value-1+props.images.length)%props.images.length;</script>